import { create } from 'zustand'
import type { Watermark, QRConfig } from '../types'

interface DecorationState {
  watermark: Watermark | null
  qrConfig: QRConfig
  setWatermark: (watermark: Watermark | null) => void
  setQRConfig: (config: Partial<QRConfig>) => void
}

const defaultQRConfig: QRConfig = {
  enabled: false,
  content: '',
  size: 40,
  position: 'bottom-right',
}

export const useDecorationStore = create<DecorationState>((set, get) => ({
  watermark: null,
  qrConfig: defaultQRConfig,
  setWatermark: (watermark) => set({ watermark }),
  setQRConfig: (config) => set({ qrConfig: { ...get().qrConfig, ...config } }),
}))

import { useEffect } from 'react'
import { useShallow } from 'zustand/shallow'
import { useContactStore } from '../../stores/contactStore'
import { usePreviewStore } from '../../stores/previewStore'
import { useDecorationStore } from '../../stores/decorationStore'
import LabelCanvas, { DEFAULT_TEMPLATE } from './LabelCanvas'
import WatermarkLayer from './WatermarkLayer'
import QROverlay from './QROverlay'
import type { Contact, Template, Watermark, QRConfig } from '../../types'

const ZOOM_MIN = 0.5
const ZOOM_MAX = 4.0
const ZOOM_STEP = 0.25

export default function PreviewArea() {
  const { contacts, selectedIds } = useContactStore(
    useShallow((s) => ({ contacts: s.contacts, selectedIds: s.selectedIds })),
  )
  const { zoom, selectedTemplate, previewContactIndex, setZoom, setPreviewContactIndex } =
    usePreviewStore(
      useShallow((s) => ({
        zoom: s.zoom,
        selectedTemplate: s.selectedTemplate,
        previewContactIndex: s.previewContactIndex,
        setZoom: s.setZoom,
        setPreviewContactIndex: s.setPreviewContactIndex,
      })),
    )
  const { watermark, qrConfig } = useDecorationStore(
    useShallow((s) => ({ watermark: s.watermark, qrConfig: s.qrConfig })),
  )

  const selectedContacts = contacts.filter((c) => selectedIds.has(c.id))

  // 選択件数が減ったときにインデックスを範囲内にクランプ
  useEffect(() => {
    if (selectedContacts.length === 0) return
    const clamped = Math.min(previewContactIndex, selectedContacts.length - 1)
    if (clamped !== previewContactIndex) {
      setPreviewContactIndex(clamped)
    }
  }, [selectedContacts.length, previewContactIndex, setPreviewContactIndex])

  const safeIndex = Math.max(0, Math.min(previewContactIndex, selectedContacts.length - 1))
  const currentContact: Contact | null = selectedContacts[safeIndex] ?? null

  const template: Template = selectedTemplate ?? DEFAULT_TEMPLATE

  const zoomIn = () => setZoom(Math.min(ZOOM_MAX, Math.round((zoom + ZOOM_STEP) * 100) / 100))
  const zoomOut = () => setZoom(Math.max(ZOOM_MIN, Math.round((zoom - ZOOM_STEP) * 100) / 100))
  const zoomReset = () => setZoom(1)

  return (
    <div className="flex-1 flex flex-col overflow-hidden bg-[#f0f0f0]">
      {/* ツールバー */}
      <div className="flex items-center gap-3 px-4 py-2 bg-white border-b border-gray-200 shrink-0">
        <span className="text-sm font-medium text-gray-700 mr-auto">
          {template.name}
          {selectedContacts.length > 0 && (
            <span className="ml-2 text-xs text-gray-400">
              {safeIndex + 1} / {selectedContacts.length} 件
            </span>
          )}
        </span>
        {/* ズームコントロール */}
        <div className="flex items-center gap-1">
          <button
            onClick={zoomOut}
            disabled={zoom <= ZOOM_MIN}
            className="px-2 py-1 text-sm rounded border border-gray-300 hover:bg-gray-100 disabled:opacity-40"
            aria-label="ズームアウト"
          >
            −
          </button>
          <button
            onClick={zoomReset}
            className="px-3 py-1 text-xs rounded border border-gray-300 hover:bg-gray-100 min-w-[52px] text-center"
          >
            {Math.round(zoom * 100)}%
          </button>
          <button
            onClick={zoomIn}
            disabled={zoom >= ZOOM_MAX}
            className="px-2 py-1 text-sm rounded border border-gray-300 hover:bg-gray-100 disabled:opacity-40"
            aria-label="ズームイン"
          >
            ＋
          </button>
        </div>
      </div>

      {/* キャンバスエリア */}
      <div className="flex-1 overflow-auto flex items-center justify-center p-6">
        {currentContact ? (
          <LabelStack
            contact={currentContact}
            template={template}
            zoom={zoom}
            watermark={watermark}
            qrConfig={qrConfig}
          />
        ) : (
          <p className="text-gray-400 text-sm">住所録から連絡先を選択してください</p>
        )}
      </div>

      {/* サムネイルナビゲーション (複数選択時) */}
      {selectedContacts.length > 1 && (
        <div className="shrink-0 bg-white border-t border-gray-200 px-4 py-2 flex gap-2 overflow-x-auto">
          {selectedContacts.map((c, i) => (
            <button
              key={c.id}
              onClick={() => setPreviewContactIndex(i)}
              className={`shrink-0 flex flex-col items-center gap-1 p-1 rounded border-2 transition-colors ${
                i === safeIndex
                  ? 'border-blue-500 bg-blue-50'
                  : 'border-transparent hover:border-gray-300'
              }`}
              title={`${c.familyName} ${c.givenName}`}
            >
              {/* サムネイル */}
              <div className="overflow-hidden rounded" style={{ transform: 'scale(1)', transformOrigin: 'top left' }}>
                <LabelStack
                  contact={c}
                  template={template}
                  zoom={0.35}
                  watermark={watermark}
                  qrConfig={qrConfig}
                />
              </div>
              <span className="text-[10px] text-gray-600 max-w-[80px] truncate">
                {c.familyName} {c.givenName}
              </span>
            </button>
          ))}
        </div>
      )}
    </div>
  )
}

/** LabelCanvas + WatermarkLayer + QROverlay の積み重ねコンテナ */
interface LabelStackProps {
  contact: Contact
  template: Template
  zoom: number
  watermark: Watermark | null
  qrConfig: QRConfig
}

function LabelStack({ contact, template, zoom, watermark, qrConfig }: LabelStackProps) {
  return (
    <div className="relative shadow-md" style={{ display: 'inline-block' }}>
      <LabelCanvas contact={contact} template={template} zoom={zoom} />
      <WatermarkLayer
        watermark={watermark}
        labelWidth={template.labelWidth}
        labelHeight={template.labelHeight}
        zoom={zoom}
      />
      <QROverlay
        qrConfig={qrConfig}
        labelWidth={template.labelWidth}
        labelHeight={template.labelHeight}
        zoom={zoom}
      />
    </div>
  )
}

import { useEffect, useRef } from 'react'
import type { Watermark } from '../../types'

const MM_TO_PX = 96 / 25.4

/** プリセット透かし絵文字マップ */
const PRESET_EMOJIS: Record<string, string> = {
  sakura: '🌸',
  wave: '🌊',
  bamboo: '🎋',
  fuji: '🗻',
  crane: '🦢',
}

interface WatermarkLayerProps {
  watermark: Watermark | null
  labelWidth: number   // mm
  labelHeight: number  // mm
  zoom: number
}

export default function WatermarkLayer({
  watermark,
  labelWidth,
  labelHeight,
  zoom,
}: WatermarkLayerProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  const canvasW = Math.round(labelWidth * MM_TO_PX * zoom)
  const canvasH = Math.round(labelHeight * MM_TO_PX * zoom)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    const dpr = window.devicePixelRatio || 1
    canvas.width = canvasW * dpr
    canvas.height = canvasH * dpr
    canvas.style.width = `${canvasW}px`
    canvas.style.height = `${canvasH}px`
    ctx.scale(dpr, dpr)

    ctx.clearRect(0, 0, canvasW, canvasH)

    if (!watermark || watermark.id === 'none') return

    ctx.globalAlpha = watermark.opacity

    if (watermark.type === 'preset') {
      const emoji = PRESET_EMOJIS[watermark.id]
      if (emoji) {
        drawEmojiPattern(ctx, emoji, canvasW, canvasH, zoom)
      }
    } else if (watermark.type === 'custom' && watermark.filePath) {
      const img = new Image()
      const opacity = watermark.opacity

      img.onload = () => {
        ctx.globalAlpha = opacity
        // ラベル全体に引き伸ばして描画
        ctx.drawImage(img, 0, 0, canvasW, canvasH)
      }
      img.src = watermark.filePath

      return () => {
        img.onload = null
        img.src = ''
      }
    }
  }, [watermark, canvasW, canvasH, zoom])

  return (
    <canvas
      ref={canvasRef}
      className="absolute inset-0 pointer-events-none"
      style={{ width: canvasW, height: canvasH }}
    />
  )
}

/** 絵文字をタイル状に描画する */
function drawEmojiPattern(
  ctx: CanvasRenderingContext2D,
  emoji: string,
  w: number,
  h: number,
  zoom: number,
) {
  const fontSize = Math.round(18 * zoom)
  ctx.font = `${fontSize}px sans-serif`
  ctx.textAlign = 'center'
  ctx.textBaseline = 'middle'

  const step = Math.round(fontSize * 2.2)
  const offsetX = step / 2

  let row = 0
  for (let y = fontSize; y < h + fontSize; y += step) {
    const xStart = row % 2 === 0 ? fontSize : fontSize + offsetX
    for (let x = xStart; x < w + fontSize; x += step) {
      ctx.fillText(emoji, x, y)
    }
    row++
  }
}

import { useEffect, useRef } from 'react'
import QRCode from 'qrcode'
import type { QRConfig } from '../../types'

const MM_TO_PX = 96 / 25.4

interface QROverlayProps {
  qrConfig: QRConfig
  labelWidth: number   // mm
  labelHeight: number  // mm
  zoom: number
}

export default function QROverlay({
  qrConfig,
  labelWidth,
  labelHeight,
  zoom,
}: QROverlayProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  const canvasW = Math.round(labelWidth * MM_TO_PX * zoom)
  const canvasH = Math.round(labelHeight * MM_TO_PX * zoom)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    const dpr = window.devicePixelRatio || 1
    canvas.width = canvasW * dpr
    canvas.height = canvasH * dpr
    canvas.style.width = `${canvasW}px`
    canvas.style.height = `${canvasH}px`
    ctx.scale(dpr, dpr)

    ctx.clearRect(0, 0, canvasW, canvasH)

    if (!qrConfig.enabled || !qrConfig.content) return

    let cancelled = false

    const qrSize = Math.round(qrConfig.size * zoom)
    const padding = Math.round(4 * zoom)
    const { x, y } = resolvePosition(qrConfig.position, canvasW, canvasH, qrSize, padding)

    // 一時 canvas に QR を描画してから貼り付け
    const tmpCanvas = document.createElement('canvas')
    QRCode.toCanvas(tmpCanvas, qrConfig.content, {
      width: qrSize,
      margin: 1,
      color: { dark: '#000000', light: '#ffffff' },
    })
      .then(() => {
        if (cancelled) return
        ctx.clearRect(0, 0, canvasW, canvasH)
        // 白背景パディング
        ctx.fillStyle = '#ffffff'
        ctx.fillRect(x - 2, y - 2, qrSize + 4, qrSize + 4)
        ctx.drawImage(tmpCanvas, x, y, qrSize, qrSize)
      })
      .catch(() => {
        // content が無効な場合は無視
      })

    return () => {
      cancelled = true
    }
  }, [qrConfig, canvasW, canvasH, zoom])

  return (
    <canvas
      ref={canvasRef}
      className="absolute inset-0 pointer-events-none"
      style={{ width: canvasW, height: canvasH }}
    />
  )
}

function resolvePosition(
  position: QRConfig['position'],
  canvasW: number,
  canvasH: number,
  qrSize: number,
  padding: number,
): { x: number; y: number } {
  switch (position) {
    case 'top-left':
      return { x: padding, y: padding }
    case 'top-right':
      return { x: canvasW - qrSize - padding, y: padding }
    case 'bottom-left':
      return { x: padding, y: canvasH - qrSize - padding }
    case 'bottom-right':
      return { x: canvasW - qrSize - padding, y: canvasH - qrSize - padding }
  }
}

import { useState } from 'react'
import type { View } from './types'
import ContactList from './components/address/ContactList'
import PreviewArea from './components/preview/PreviewArea'

function App() {
  const [view, setView] = useState<View>('contacts')

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900">
      {/* サイドバー */}
      <nav className="w-48 bg-white border-r border-gray-200 flex flex-col p-3 gap-1 shrink-0">
        <h1 className="text-sm font-bold px-2 py-3 text-gray-700">Atena ラベル印刷</h1>
        <NavButton active={view === 'contacts'} onClick={() => setView('contacts')}>
          住所録
        </NavButton>
        <NavButton active={view === 'preview'} onClick={() => setView('preview')}>
          ラベルプレビュー
        </NavButton>
        <NavButton active={view === 'settings'} onClick={() => setView('settings')}>
          設定
        </NavButton>
      </nav>

      {/* メインコンテンツ */}
      <main className="flex-1 flex overflow-hidden">
        {view === 'contacts' && (
          <div className="w-72 border-r border-gray-200 bg-white flex flex-col h-full">
            <ContactList />
          </div>
        )}
        {view === 'contacts' && <PreviewArea />}
        {view === 'preview' && <PreviewArea />}
        {view === 'settings' && (
          <div className="flex-1 p-6">
            <h2 className="text-xl font-semibold mb-4">設定</h2>
            <p className="text-gray-500">Phase 6 で実装予定</p>
          </div>
        )}
      </main>
    </div>
  )
}

function NavButton({
  active,
  onClick,
  children,
}: {
  active: boolean
  onClick: () => void
  children: React.ReactNode
}) {
  return (
    <button
      onClick={onClick}
      className={`text-left px-3 py-2 rounded-md text-sm transition-colors ${
        active
          ? 'bg-blue-50 text-blue-700 font-medium'
          : 'text-gray-600 hover:bg-gray-100'
      }`}
    >
      {children}
    </button>
  )
}

export default App

